pub const CommonBehavior = struct {
    type: u8,
    data: u8,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeByte(self.type);
        writer.writeByte(self.data);
    }

    pub fn decode(reader: *std.Io.Reader) DecodeError!@This() {
        const @"type" = try reader.takeByte();
        const data = try reader.takeByte();
        return .{
            .type = @"type",
            .data = data,
        };
    }

};

pub const CountedString16 = struct {
    string: []const u8,
    alignment_pad: []const u8,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeInt(u16, @intCast(self.string.len));
        writer.write(self.string);
        writer.write(self.alignment_pad);
    }

    pub fn decode(allocator: std.mem.Allocator, reader: *std.Io.Reader) AllocDecodeError!@This() {
        const length = try reader.takeInt(u16, .native);
        const string_byte_len = @as(usize, length);
        const string_temp = try reader.take(string_byte_len);
        const string = try allocator.dupe(u8, string_temp);
        const alignment_pad_byte_len = @as(usize, (((length + 5) & (~3)) - (length + 2)));
        const alignment_pad_temp = try reader.take(alignment_pad_byte_len);
        const alignment_pad = try allocator.dupe(u8, alignment_pad_temp);
        return .{
            .string = string,
            .alignment_pad = alignment_pad,
        };
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.string);
        allocator.free(self.alignment_pad);
    }

};

