        };
    }

};

pub const DeviceLedInfo = struct {
    ledClass: LedClass,
    ledID: u16,
    namesPresent: u32,
    mapsPresent: u32,
    physIndicators: u32,
    state: u32,
    names: []const xproto.Atom,
    maps: []IndicatorMap,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeInt(u16, @intCast(@intFromEnum(self.ledClass)));
        writer.writeInt(u16, self.ledID);
        writer.writeInt(u32, self.namesPresent);
        writer.writeInt(u32, self.mapsPresent);
        writer.writeInt(u32, self.physIndicators);
        writer.writeInt(u32, self.state);
        for (self.names) |elem| {
            writer.writeInt(u32, @intFromEnum(elem));
        }
        for (self.maps) |elem| {
            elem.encode(writer);
        }
    }

    pub fn decode(allocator: std.mem.Allocator, reader: *std.Io.Reader) AllocDecodeError!@This() {
        const ledClass = @as(LedClass, @enumFromInt(try reader.takeInt(u16, .native)));
        const ledID = try reader.takeInt(u16, .native);
        const namesPresent = try reader.takeInt(u32, .native);
        const mapsPresent = try reader.takeInt(u32, .native);
        const physIndicators = try reader.takeInt(u32, .native);
        const state = try reader.takeInt(u32, .native);
        const names = try allocator.alloc(xproto.Atom, @as(usize, @popCount(namesPresent)));
        errdefer allocator.free(names);
        var names_decoded: usize = 0;
        for (names) |*elem| {
            const elem_value = @as(xproto.Atom, @enumFromInt(try reader.takeInt(u32, .native)));
            elem.* = elem_value;
            names_decoded += 1;
        }
        const maps = try allocator.alloc(IndicatorMap, @as(usize, @popCount(mapsPresent)));
        errdefer allocator.free(maps);
        var maps_decoded: usize = 0;
        for (maps) |*elem| {
            const elem_value = try IndicatorMap.decode(reader);
            elem.* = elem_value;
            maps_decoded += 1;
        }
        return .{
            .ledClass = ledClass,
            .ledID = ledID,
            .namesPresent = namesPresent,
            .mapsPresent = mapsPresent,
            .physIndicators = physIndicators,
            .state = state,
            .names = names,
            .maps = maps,
        };
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.names);
        allocator.free(self.maps);
    }

};

pub const IndicatorMap = struct {
    flags: IMFlag,
    whichGroups: IMGroupsWhich,
    groups: SetOfGroup,
    whichMods: IMModsWhich,
    mods: u8,
    realMods: u8,
    vmods: u16,
    ctrls: u32,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeByte(@intCast(@intFromEnum(self.flags)));
        writer.writeByte(@intCast(@intFromEnum(self.whichGroups)));
        writer.writeByte(@intCast(@intFromEnum(self.groups)));
        writer.writeByte(@intCast(@intFromEnum(self.whichMods)));
        writer.writeByte(self.mods);
        writer.writeByte(self.realMods);
        writer.writeInt(u16, self.vmods);
        writer.writeInt(u32, self.ctrls);
    }

    pub fn decode(reader: *std.Io.Reader) DecodeError!@This() {
        const flags = @as(IMFlag, @enumFromInt(try reader.takeInt(u8, .native)));
        const whichGroups = @as(IMGroupsWhich, @enumFromInt(try reader.takeInt(u8, .native)));
        const groups = @as(SetOfGroup, @enumFromInt(try reader.takeInt(u8, .native)));
        const whichMods = @as(IMModsWhich, @enumFromInt(try reader.takeInt(u8, .native)));
        const mods = try reader.takeByte();
        const realMods = try reader.takeByte();
        const vmods = try reader.takeInt(u16, .native);
        const ctrls = try reader.takeInt(u32, .native);
        return .{
            .flags = flags,
            .whichGroups = whichGroups,
            .groups = groups,
            .whichMods = whichMods,
            .mods = mods,
            .realMods = realMods,
            .vmods = vmods,
            .ctrls = ctrls,
        };
    }

};

pub const KTMapEntry = struct {
