    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeByte(@intFromBool(self.active));
        writer.writeByte(self.mods_mask);
        writer.writeByte(self.level);
        writer.writeByte(self.mods_mods);
        writer.writeInt(u16, self.mods_vmods);
        writer.splatByte(0, 2);
    }

    pub fn decode(reader: *std.Io.Reader) DecodeError!@This() {
        const active = (try reader.takeByte()) != 0;
        const mods_mask = try reader.takeByte();
        const level = try reader.takeByte();
        const mods_mods = try reader.takeByte();
        const mods_vmods = try reader.takeInt(u16, .native);
        _ = try reader.take(2);
        return .{
            .active = active,
            .mods_mask = mods_mask,
            .level = level,
            .mods_mods = mods_mods,
            .mods_vmods = mods_vmods,
        };
    }

};

