pub const KeySymMap = struct {
    kt_index: [4]u8,
    groupInfo: u8,
    width: u8,
    syms: []const u32,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.write(self.kt_index[0..]);
        writer.writeByte(self.groupInfo);
        writer.writeByte(self.width);
        writer.writeInt(u16, @intCast(self.syms.len));
        for (self.syms) |elem| {
            writer.writeInt(u32, elem);
        }
    }

    pub fn decode(allocator: std.mem.Allocator, reader: *std.Io.Reader) AllocDecodeError!@This() {
        var kt_index: [4]u8 = undefined;
        @memcpy(kt_index[0..], try reader.take(4));
        const groupInfo = try reader.takeByte();
        const width = try reader.takeByte();
        const nSyms = try reader.takeInt(u16, .native);
        const syms = try allocator.alloc(u32, @as(usize, nSyms));
        errdefer allocator.free(syms);
        var syms_decoded: usize = 0;
        for (syms) |*elem| {
            const elem_value = try reader.takeInt(u32, .native);
            elem.* = elem_value;
            syms_decoded += 1;
        }
        return .{
            .kt_index = kt_index,
            .groupInfo = groupInfo,
            .width = width,
            .syms = syms,
        };
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.syms);
    }

};

pub const KeyType = struct {
    mods_mask: u8,
    mods_mods: u8,
    mods_vmods: u16,
    numLevels: u8,
    hasPreserve: bool,
    map: []KTMapEntry,
    preserve: []ModDef,

    pub fn encode(self: @This(), writer: anytype) void {
        writer.writeByte(self.mods_mask);
        writer.writeByte(self.mods_mods);
        writer.writeInt(u16, self.mods_vmods);
        writer.writeByte(self.numLevels);
        writer.writeByte(@intCast(self.map.len));
        writer.writeByte(@intFromBool(self.hasPreserve));
        writer.splatByte(0, 1);
        for (self.map) |elem| {
            elem.encode(writer);
        }
        for (self.preserve) |elem| {
            elem.encode(writer);
        }
    }

    pub fn decode(allocator: std.mem.Allocator, reader: *std.Io.Reader) AllocDecodeError!@This() {
        const mods_mask = try reader.takeByte();
        const mods_mods = try reader.takeByte();
        const mods_vmods = try reader.takeInt(u16, .native);
        const numLevels = try reader.takeByte();
        const nMapEntries = try reader.takeByte();
        const hasPreserve = (try reader.takeByte()) != 0;
        _ = try reader.take(1);
        const map = try allocator.alloc(KTMapEntry, @as(usize, nMapEntries));
        errdefer allocator.free(map);
        var map_decoded: usize = 0;
        for (map) |*elem| {
            const elem_value = try KTMapEntry.decode(reader);
            elem.* = elem_value;
            map_decoded += 1;
        }
        const preserve = try allocator.alloc(ModDef, @as(usize, (hasPreserve * nMapEntries)));
        errdefer allocator.free(preserve);
        var preserve_decoded: usize = 0;
        for (preserve) |*elem| {
            const elem_value = try ModDef.decode(reader);
            elem.* = elem_value;
            preserve_decoded += 1;
        }
        return .{
            .mods_mask = mods_mask,
            .mods_mods = mods_mods,
            .mods_vmods = mods_vmods,
            .numLevels = numLevels,
            .hasPreserve = hasPreserve,
            .map = map,
            .preserve = preserve,
        };
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.map);
        allocator.free(self.preserve);
    }

};

